sql:
SELECT SUM(quantityOrdered) AS totalQuantityOrdered
FROM order_details
WHERE orderNumber = 10100;

external_knowledge:
- 'sales representatives' refers to employees who handle orders;
- 'more than five orders' indicates that the count of orders is greater than 5;
- 'total sales' is the sum of the total cost of all orders handled by each sales representative.

- 'Top sales representatives' refers to those with the highest total revenue generated;
- 'Total revenue' includes all revenue from shipped orders;
- 'Sales representatives' are identified by their first and last names combined.

- The term "top sales representatives" refers to those with the highest total revenue;
- "Total revenue" is calculated by summing the `orderTotal` for each sales representative;
- "Total orders" is the count of `orderNumber` for each sales representative.

sql:
SELECT DISTINCT orderType, orderNumber
FROM orders
ORDER BY orderType;

SELECT AVG(total_payment) AS average_total_payment
FROM (
    SELECT customerNumber, SUM(amount) AS total_payment
    FROM payments
    GROUP BY customerNumber
) AS customer_payments;

